$(function(){$(".delete-modal-button").on("click",function(){$(".delete-modal").modal("show")});$("#abcSelect").on("change",function(){window.location.href="/voedingsmiddel/letter/"+$(this).val()});$('input[name="recipe[isSelfInvented]"]').on("change",function(){if($(this).val()==="1"){$("#recipeSource").hide()}else{$("#recipeSource").show()}});$("#recipeFilterIcon").on("click",function(){let form=$("#filter-sort-form");if(form.hasClass("d-none")){form.removeClass("d-none")}else{form.addClass("d-none")}});$('form[name="rating"]').on("submit",function(event){let rating=$("#rating_rating");rating.text("");if(rating.val()<1||rating.val()>10){$("#formErrorsClient").text("The beoordeling moet tussen 1 en 10 zijn.");event.preventDefault()}});$("body form").on("submit",function(event){$(this).each(function(){let dateFields=$(".date-field");dateFields.each(function(){let dateStr=$(this).val();const regex=/^\d{2}-\d{2}-\d{4}$/;if(dateStr.match(regex)===null){if(dateFields.length===1){$("#formErrorsClient").text("De datum moet in het formaat dd-mm-jjjj.")}else{$("#formErrorsClient").text("De datums moeten in het formaat dd-mm-jjjj.")}event.preventDefault()}else{let daysPerMonth=[31,29,31,30,31,30,31,31,30,31,30,31];let dateArray=dateStr.split("-");let year=parseInt(dateArray[2]);let month=parseInt(dateArray[1]);let day=parseInt(dateArray[0]);if(year%4!==0&&month===2&&day===29){$("#formErrorsClient").text("Ongeldige datum.");event.preventDefault()}if(month>12||month<1){$("#formErrorsClient").text("Ongeldige datum.");event.preventDefault()}if(day>daysPerMonth[month-1]||day<1){$("#formErrorsClient").text("Ongeldige datum.");event.preventDefault()}if(year<1900){$("#formErrorsClient").text("Het jaar mag niet voor 1900 liggen.");event.preventDefault()}if($(this).hasClass("no-future")){let time=new Date(year+"-"+month+"-"+day);if(time.getTime()>Date.now()){$("#formErrorsClient").text("De datum mag niet in de toekomst liggen.");event.preventDefault()}}}})})})});